function waterfall(container){
	function getMargin(element, side){
		var styles = window.getComputedStyle(element);
		return parseFloat(styles["margin" + side]) || 0;
	}

	function px(value){
		return value + "px";
	}

	function top(element){
		return parseFloat(element.style.top) || 0;
	}

	function left(element){
		return parseFloat(element.style.left) || 0;
	}

	function width(element){
		return element.clientWidth;
	}

	function height(element){
		return element.clientHeight;
	}

	function bottom(element){
		return top(element) + height(element) + getMargin(element, "Bottom");
	}

	function right(element){
		return left(element) + width(element) + getMargin(element, "Right");
	}

	function sortByBottom(elements){
		elements.sort(function(prev, next){
			var prevBottom = bottom(prev);
			var nextBottom = bottom(next);
			return prevBottom === nextBottom ? left(next) - left(prev) : nextBottom - prevBottom;
		});
	}

	if (typeof container === "string") {
		container = document.querySelector(container);
	}

	if (!container) {
		return Promise.resolve();
	}

	var items = Array.from(container.children).map(function(item){
		item.style.position = "absolute";
		return item;
	});

	if (!items.length) {
		container.style.height = "0px";
		return Promise.resolve();
	}

	container.style.position = "relative";

	var images = Array.from(container.querySelectorAll("img"));
	var waitImages = images.map(function(image){
		return new Promise(function(resolve){
			if (image.complete) {
				resolve();
				return;
			}
			image.addEventListener("load", resolve, { once: true });
			image.addEventListener("error", resolve, { once: true });
		});
	});

	return Promise.all(waitImages).then(function(){
		var containerWidth = width(container);
		if (!containerWidth) {
			return;
		}

		var currentRow = [];
		items[0].style.top = "0px";
		items[0].style.left = px(getMargin(items[0], "Left"));
		currentRow.push(items[0]);

		for (var index = 1; index < items.length; index++) {
			var prev = items[index - 1];
			var item = items[index];
			if (right(prev) + width(item) > containerWidth) {
				break;
			}
			item.style.top = prev.style.top;
			item.style.left = px(right(prev));
			currentRow.push(item);
		}

		for (var columnIndex = currentRow.length; columnIndex < items.length; columnIndex++) {
			sortByBottom(currentRow);
			var nextItem = items[columnIndex];
			var anchor = currentRow.pop();
			nextItem.style.top = px(bottom(anchor) + getMargin(nextItem, "Top"));
			nextItem.style.left = px(left(anchor));
			currentRow.push(nextItem);
		}

		sortByBottom(currentRow);
		var tallest = currentRow[0];
		container.style.height = px(bottom(tallest) + getMargin(tallest, "Bottom"));

		function handleResize(event){
			if (width(container) !== containerWidth) {
				window.removeEventListener(event.type, handleResize);
				waterfall(container);
			}
		}

		window.addEventListener("resize", handleResize);
	});
}